import{_ as a,o as t,c as n,ae as i}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Deep Linking Overview","description":"","frontmatter":{"title":"Deep Linking Overview","slug":"deep-linking"},"headers":[],"relativePath":"marketer-hub/deep-linking.md","filePath":"marketer-hub/deep-linking.md"}'),r={name:"marketer-hub/deep-linking.md"};function o(l,e,s,p,c,h){return t(),n("div",null,[...e[0]||(e[0]=[i('<p>.png &quot;Contextual_Deep_Link.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch deep linking gives you peace of mind that your links will work in every edge case to route users to the best destination with the industry&#39;s highest matching accuracy, by combining every deep linking standard into a single, simple package. Easy to implement, and always up to date.</p><h3 id="deep-linking-use-cases" tabindex="-1">Deep linking use cases: <a class="header-anchor" href="#deep-linking-use-cases" aria-label="Permalink to &quot;Deep linking use cases:&quot;">​</a></h3><ul><li>Direct deep linking users who have the app installed already to relevant content.</li><li>Deferred deep linking users who do not have the app installed to relevant content immediately after the first install.</li><li>Customized/branded URLs.</li><li>Store custom data parameters in link data.</li></ul><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><ol><li><p>User clicks a link.</p><ol><li><p>If user has the app installed, then the app opens and routes to relevant content.</p></li><li><p>If user doesn&#39;t have the app installed, then:</p><ol><li>User is routed to App/Play store to download the app, then routed to relevant content when they open the app, or</li><li>User is routed to relevant mobile web content.</li></ol></li></ol></li></ol><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h2><p>Access to Branch Deep Linking requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="getting-started" tabindex="-1">Getting started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting started&quot;">​</a></h2><p>To implement Branch deep linking, you&#39;ll need to work with your development team to integrate the Branch SDKs into your mobile app and configure deep link routing. See our <a href="./deep-linking-for-developers.html">developer documentation</a> for implementation details.</p><h2 id="creating-branch-links" tabindex="-1">Creating Branch Links <a class="header-anchor" href="#creating-branch-links" aria-label="Permalink to &quot;Creating Branch Links&quot;">​</a></h2><p>You can create Branch Links directly without developer involvement using these tools:</p><ul><li><p><a href="./create-quick-links.html">Short Link</a></p><ul><li>Ideal for one-off campaigns, especially social media, blog posts, etc.</li></ul></li><li><p><a href="https://chromewebstore.google.com/detail/branch-link-creator/pekdpppibljpmpbcjelehhnldnfbglgf" target="_blank" rel="noreferrer">Chrome Extension</a></p></li></ul><p>For programmatic link generation at scale, your development team can use APIs and SDKs. See our <a href="./deep-linking-for-developers.html#3-create-your-branch-link">developer documentation</a> for these advanced options.</p><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><h3 id="understanding-canonical-urls" tabindex="-1">Understanding canonical URLs <a class="header-anchor" href="#understanding-canonical-urls" aria-label="Permalink to &quot;Understanding canonical URLs&quot;">​</a></h3><p>A canonical URL represents the corresponding web URL for your in-app content. If your app can already deep link using web URLs, using canonical URLs for deep link routing can reduce implementation effort, as this URL is often automatically applied as Branch Link data for products like Journeys and Email.</p><p>For example, a shopping brand that has both a website and a mobile app will have equivalent experiences for the user to get to related content and it can be identified with a canonical URL. A web URL might look something like this:</p><p><code>https://www.myshop.com/category/productName</code></p><p>For a hotel/travel brand, a canonical URL might look something like this:</p><p><code>https://www.mytravel.com/Hotel-Search?rooms=1&amp;adults=2&amp;destination=Bangkok%20(BKK%20-%20Suvarnabhumi%20Intl.)&amp;regionId=4934466&amp;latLong=13.687353%2C100.74995&amp;startDate=2021-09-23&amp;endDate=2021-09-24&amp;d1=2021-09-23&amp;d2=2021-09-24</code></p><p>The different parts of the URL can be used for deep linking the user to in-app content. See our <a href="./deep-linking-for-developers.html#best-practices">developer documentation</a> for implementation details.</p><h3 id="enhancing-link-appearance-with-open-graph-tags" tabindex="-1">Enhancing link appearance with Open Graph tags <a class="header-anchor" href="#enhancing-link-appearance-with-open-graph-tags" aria-label="Permalink to &quot;Enhancing link appearance with Open Graph tags&quot;">​</a></h3><p>When creating your Branch Link, you can add <a href="https://ogp.me/" target="_blank" rel="noreferrer">Open Graph</a> tags to enhance its look and feel in a social graph. Adding these tags should make your Branch Link look better in channels like SMS or on social media posts.</p><p>Open Graph tags are automatically set when configuring Social Media Tags in the Branch Link creation interface, or scraped from your website when using certain URL parameters. See our <a href="./deep-linking-for-developers.html#open-graph-tags-in-branch-links">developer documentation</a> for technical configuration details.</p><p>.png &quot;Screen Shot 2021-09-28 at 2.22.55 PM.png&quot;)</p>',27)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
